  `created_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_login_risk_user` (`user_id`),
  KEY `idx_login_risk_ts` (`ts`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

DROP TABLE IF EXISTS `security_event`;
